from typing import Set, List, Optional, Iterable

from geosat.cloud import PointCloud
from geosat.cloud.extractor import CloudExtractor

from geosat.psanp.abstractions.classifier import Classifier
from geosat.psanp.abstractions.option import Option
from geosat.psanp.abstractions.pipelinemetadata import PipelineMetadata


class NoiseClassifier(Classifier):
    """A classifier that identifies cluster of points that are low density,
    and marks them as noise.
    """

    def __init__(self, gsd=0.25, min_point_count=250, stage_name: Optional[str] = None):
        super().__init__(stage_name)
        self.gsd = gsd
        self.min_point_count = min_point_count
        self.output_class = "noise"

    @classmethod
    def options(cls) -> List[Option]:
        return [
            Option("gsd", "size of voxel used", type_cast=float, required=False),
            Option(
                "min_point_count",
                "groups of voxels with less than min_point_count are considered noise",
                type_cast=float,
                required=False,
            ),
        ]

    def execute_on(
        self, cloud: PointCloud, pipeline_metadata: PipelineMetadata
    ) -> Iterable[PointCloud]:
        class_code = pipeline_metadata.classification_codes[self.output_class]
        extractor = CloudExtractor(cloud, self.gsd)
        noise_points = extractor.filter_small_object(self.min_point_count)
        cloud.classification[noise_points] = class_code

        return (cloud,)

    def input_classes(self) -> Set[str]:
        return set()

    def output_classes(self) -> Set[str]:
        return {self.output_class}
